const express = require('express');
const http = require('http');
const { Server } = require('socket.io');
const crypto = require('crypto');

const app = express();
app.use(express.json());

const server = http.createServer(app);
const io = new Server(server, {
  cors: {
    origin: '*',
    methods: ['GET', 'POST']
  }
});

const PORT = process.env.PORT || 3000;
const SESSION_TTL_MS = 1000 * 60 * 60 * 24;

const users = new Map();
const sessions = new Map();
const leaderboard = new Map();

function now() {
  return Date.now();
}

function generateId(bytes = 16) {
  return crypto.randomBytes(bytes).toString('hex');
}

function isValidUsername(username) {
  return typeof username === 'string' && username.trim().length >= 3 && username.trim().length <= 20;
}

function isValidPassword(password) {
  return typeof password === 'string' && password.length >= 6 && password.length <= 128;
}

function isValidScore(score) {
  return Number.isFinite(score) && score >= 0;
}

function createSession(username) {
  const sessionId = generateId(24);
  sessions.set(sessionId, {
    username,
    createdAt: now(),
    lastSeenAt: now()
  });
  return sessionId;
}

function getSession(sessionId) {
  const session = sessions.get(sessionId);
  if (!session) return null;
  if (now() - session.createdAt > SESSION_TTL_MS) {
    sessions.delete(sessionId);
    return null;
  }
  session.lastSeenAt = now();
  return session;
}

function requireSession(socket) {
  const sessionId = socket.handshake.auth && socket.handshake.auth.sessionId;
  if (!sessionId) return null;
  return getSession(sessionId);
}

function updateLeaderboard(username, score) {
  const current = leaderboard.get(username);
  if (!current || score > current.score) {
    leaderboard.set(username, {
      username,
      score,
      updatedAt: now()
    });
  }
}

function getTopLeaderboard(limit = 10) {
  return Array.from(leaderboard.values())
    .sort((a, b) => b.score - a.score || a.updatedAt - b.updatedAt)
    .slice(0, limit);
}

function cleanupExpiredSessions() {
  const cutoff = now() - SESSION_TTL_MS;
  for (const [sessionId, session] of sessions.entries()) {
    if (session.createdAt < cutoff) sessions.delete(sessionId);
  }
}

setInterval(cleanupExpiredSessions, 60 * 1000).unref();

app.post('/auth/register', (req, res) => {
  const { username, password } = req.body || {};
  if (!isValidUsername(username) || !isValidPassword(password)) {
    return res.status(400).json({ error: 'Invalid username or password' });
  }

  const normalized = username.trim().toLowerCase();
  if (users.has(normalized)) {
    return res.status(409).json({ error: 'Username already exists' });
  }

  users.set(normalized, {
    username: username.trim(),
    password,
    createdAt: now()
  });

  const sessionId = createSession(username.trim());
  return res.json({ success: true, sessionId, username: username.trim() });
});

app.post('/auth/login', (req, res) => {
  const { username, password } = req.body || {};
  if (!isValidUsername(username) || !isValidPassword(password)) {
    return res.status(400).json({ error: 'Invalid username or password' });
  }

  const normalized = username.trim().toLowerCase();
  const user = users.get(normalized);
  if (!user || user.password !== password) {
    return res.status(401).json({ error: 'Invalid credentials' });
  }

  const sessionId = createSession(user.username);
  return res.json({ success: true, sessionId, username: user.username });
});

app.post('/auth/logout', (req, res) => {
  const { sessionId } = req.body || {};
  if (typeof sessionId === 'string' && sessions.has(sessionId)) {
    sessions.delete(sessionId);
  }
  res.json({ success: true });
});

app.get('/leaderboard', (req, res) => {
  res.json({
    success: true,
    leaderboard: getTopLeaderboard(10)
  });
});

io.use((socket, next) => {
  const session = requireSession(socket);
  if (!session) return next(new Error('Unauthorized'));
  socket.data.session = session;
  next();
});

io.on('connection', (socket) => {
  const { username } = socket.data.session;

  socket.emit('auth:ok', {
    username,
    sessionId: socket.handshake.auth.sessionId
  });

  socket.on('player:move', (payload = {}, ack) => {
    const { move } = payload;
    if (typeof move !== 'string' || move.length === 0) {
      if (typeof ack === 'function') ack({ success: false, error: 'Invalid move' });
      return;
    }

    if (typeof ack === 'function') ack({ success: true });
    socket.broadcast.emit('player:moved', {
      username,
      move,
      at: now()
    });
  });

  socket.on('player:score', (payload = {}, ack) => {
    const reportedUsername = typeof payload.username === 'string' ? payload.username.trim() : '';
    const score = Number(payload.score);

    if (!isValidScore(score)) {
      if (typeof ack === 'function') ack({ success: false, error: 'Invalid score' });
      return;
    }

    const scoreOwner = reportedUsername || username;
    updateLeaderboard(scoreOwner, score);

    if (typeof ack === 'function') {
      ack({ success: true, username: scoreOwner, score });
    }

    io.emit('leaderboard:update', {
      leaderboard: getTopLeaderboard(10)
    });
  });

  socket.on('disconnect', () => {
    socket.broadcast.emit('player:left', {
      username,
      at: now()
    });
  });
});

